# frozen_string_literal: true

require_relative '../../utils/basic_test_class'

module AUPSTestKit
  # The mandatory sections populated in the Composition resource.
  class AUPSRetrieveBundleCompositionMandatorySection100ballot < BasicTest
    title 'Composition contains mandatory sections with entry references'
    description 'Displays information about mandatory sections (Allergies and Intolerances, Medication Summary, Problem List) in the Composition resource, including the entry references within each section.'
    id :au_ps_retrieve_bundle_composition_mandatory_sections_100ballot

    
    run do
      read_composition_sections_info([{:id=>"Composition.section:sectionProblems", :short=>"Patient Summary Problems Section", :definition=>"Information about a patient's clinical problems or conditions that are currently being monitored.", :min=>1, :max=>"1", :required=>true, :mustSupport=>true, :code=>"11450-4", :entries=>[{:id=>"Composition.section:sectionProblems.entry:problem", :min=>0, :max=>"*", :required=>false, :mustSupport=>true, :profiles=>["Condition|http://hl7.org.au/fhir/ps/StructureDefinition/au-ps-condition"]}]}, {:id=>"Composition.section:sectionAllergies", :short=>"Patient Summary Allergies and Intolerances Section", :definition=>"Information about a patient's relevant allergies or intolerances, describing the kind of reaction (e.g. rash, anaphylaxis, etc.); preferably the agents that cause it; and optionally the criticality and the certainty of the allergy. At a minimum, this section will list currently active and any relevant historical allergies and adverse reactions. If no information about allergies is available, or if no allergies are known this is to be clearly documented in this section.", :min=>1, :max=>"1", :required=>true, :mustSupport=>true, :code=>"48765-2", :entries=>[{:id=>"Composition.section:sectionAllergies.entry:allergyOrIntolerance", :min=>0, :max=>"*", :required=>false, :mustSupport=>true, :profiles=>["AllergyIntolerance|http://hl7.org.au/fhir/ps/StructureDefinition/au-ps-allergyintolerance"]}]}, {:id=>"Composition.section:sectionMedications", :short=>"Patient Summary Medication Summary Section", :definition=>"Information about a patient's medications relevant for the scope of the patient summary.\r\nThe actual content could depend on the jurisdiction, it could report:\r\n\r\n- the currently active medications;\r\n\r\n- the current and past medications considered relevant by the authoring GP;\r\n\r\n- the patient prescriptions or dispensations automatically extracted by a regional or a national EHR.\r\n\r\nIn those cases medications are documented in the Patient Summary as medication statements or medication requests. This section requires either an entry indicating the subject is known not to be on any relevant medication; either an entry indicating that no information is available about medications; or entries summarising the subject's relevant medications.", :min=>1, :max=>"1", :required=>true, :mustSupport=>true, :code=>"10160-0", :entries=>[{:id=>"Composition.section:sectionMedications.entry:medicationStatementOrRequest", :min=>0, :max=>"*", :required=>false, :mustSupport=>true, :profiles=>["MedicationStatement|http://hl7.org.au/fhir/ps/StructureDefinition/au-ps-medicationstatement", "MedicationRequest|http://hl7.org.au/fhir/ps/StructureDefinition/au-ps-medicationrequest"]}]}], [{:expression=>"author", :label=>"author"}, {:expression=>"date", :label=>"date"}, {:expression=>"section", :label=>"section"}, {:expression=>"status", :label=>"status"}, {:expression=>"subject", :label=>"subject"}, {:expression=>"title", :label=>"title"}, {:expression=>"type", :label=>"type"}])
    end
    
  end
end
